sp_widget.client_script:
api.controller = function($timeout){

var c = this;

c.$onInit = function(){

    c.settings = c.data.settings || {};

    $timeout(function(){
        applyTheme(c.settings.theme || "light");
    },300);
};


/* APPLY THEME */

function applyTheme(theme){

    var root = document.getElementById("sp_page_root");

    if(!root) return;

    root.classList.remove("dark-theme");

    if(theme === "dark"){
        root.classList.add("dark-theme");
    }
}


/* BUTTON CLICK */

c.setTheme = function(theme){

    c.settings.theme = theme;
    applyTheme(theme);
};

};

sp_widget.css:
/* ================= LAYOUT ================= */

.sp-layouts{
  display:flex;
  max-height:calc(100vh - 64px);
  position: relative;
  background:red;
}

.sidebar-area{
  width:260px;
  max-height: calc(100vh - 64px);
}

.dmm-settings{
  flex:1;
  background:#f5f7fb;
  padding:30px;
  position: relative;
  overflow-y:auto;
  max-height:calc(100vh - 64px);
}

/* Heading*/
/* SETTINGS HEADER */

.settings-header{
  margin-bottom:20px;
}

.settings-title{
  font-size:26px;
  font-weight:600;
  margin:0;
  color:#111827;
}

.settings-title i{
  margin-right:8px;
  color:#1F8C95;
}

.settings-subtitle{
  margin-top:5px;
  color:#6b7280;
  font-size:14px;
}

/* DARK MODE SUPPORT */

body.dark-theme .settings-title{
  color:#ffffff;
}

body.dark-theme .settings-subtitle{
  color:#9ca3af;
}
/* CARD */

.card{
  background:#fff;
  border-radius:12px;
  padding:25px;
  margin-top:20px;
  box-shadow:0 4px 12px rgba(0,0,0,.04);
}

.card-title{
  font-weight:600;
  margin-bottom:20px;
}

/* INPUTS */

input,select{
  width:100%;
  padding:10px;
  border-radius:8px;
  border:1px solid #e5e7eb;
  background:#f9fafb;
}

/* SWITCH */

.toggle-row{
  display:flex;
  justify-content:space-between;
  margin:18px 0;
}

.switch{
  position:relative;
  width:40px;
  height:20px;
}

.switch input{display:none;}

.slider{
  position:absolute;
  width:100%;
  height:100%;
  background:#e5e7eb;
  border-radius:20px;
}

.slider:before{
  content:"";
  position:absolute;
  width:16px;
  height:16px;
  left:2px;
  top:2px;
  background:#fff;
  border-radius:50%;
  transition:.2s;
}

input:checked + .slider{
  background:#1F8C95;
}

input:checked + .slider:before{
  transform:translateX(20px);
}

/* BUTTON */

.btn-save{
  margin-top:20px;
  background:;
  color:#fff;
  border:none;
  padding:10px 18px;
  border-radius:8px;
}
.btn-save:hover{
 background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}
/* THEME SELECTOR */

.theme-preview{
  display:flex;
  gap:12px;
}

.theme-option{
  padding:10px 20px;
  border:1px solid #ddd;
  border-radius:10px;
  cursor:pointer;
}

.theme-option.selected{
  border:2px solid #1F8C95;
  background:#eef4ff;
}
/* ================= GLOBAL DARK MODE ================= */
/* DARK MODE */

body.dark-theme{
  background:#0b1220 !important;
  color:#e5e7eb !important;
}

body.dark-theme .sidebar-area{
  background:#020617 !important;
}

body.dark-theme .dmm-settings{
  background:#0b1220 !important;
}

body.dark-theme .card{
  background:#111827 !important;
  color:#fff !important;
}

body.dark-theme input,
body.dark-theme select{
  background:#1f2937 !important;
  color:#fff !important;
  border:1px solid #374151 !important;
}
body.dark-theme {
  background:#0b1220 !important;
  color:#e5e7eb !important;
}

/* cards */
body.dark-theme .card,
body.dark-theme .panel{
  background:#111827 !important;
  color:#ffffff !important;
}

/* sidebar */
body.dark-theme .sidebar-area{
  background:#020617 !important;
}

/* settings area */
body.dark-theme .dmm-settings{
  background:#0b1220 !important;
}

/* inputs */
body.dark-theme input,
body.dark-theme select,
body.dark-theme textarea{
  background:#1f2937 !important;
  color:#fff !important;
  border:1px solid #374151 !important;
}

/* links */
body.dark-theme a{
  color:#93c5fd !important;
}

/* button */
body.dark-theme .btn-save{
  background:#ffffff !important;
  color:#000 !important;
}

/* smooth transition */
body,
body *{
  transition:all .25s ease;
}


