color:#fff !important;
}

body.dark-theme input,
body.dark-theme select{
background:#1f2937 !important;
color:#fff !important;
border:1px solid #374151 !important;
}

.btn-save{
margin-top:20px;
padding:10px 18px;
background:#1F8C95;
color:#fff;
border:none;
border-radius:8px;
cursor:pointer;
}

.theme-preview{
display:flex;
gap:10px;
