}

sp_widget.script:
(function () {

data.side = $sp.getWidget('dmm_sidebar');

var gr = new GlideRecord('x_sysus_data_mig_0_setting');
gr.orderByDesc('sys_created_on');
gr.setLimit(1);
gr.query();

if(gr.next()){

    data.settings = {
        sys_id: gr.getUniqueValue(),
        email: gr.notification_email + "",
        batch: gr.batch_size + "",
        notify: gr.enable_notifications == true,
        logging: gr.detailed_logging == true,
        date_format: gr.date_format + "",
        timezone: gr.timezone + "",
        theme: gr.theme ? gr.theme + "" : "light"
    };

}else{

    data.settings = {
        sys_id:"",
        email:"",
        batch:"100",
        notify:false,
        logging:false,
        date_format:"YYYY-MM-DD HH:mm:ss",
        timezone:"UTC",
        theme:"light"
    };
}

/* SAVE */

if(input && input.action === "saveSettings"){

    var saveGR = new GlideRecord('x_sysus_data_mig_0_setting');

    if(input.settings.sys_id &&
       saveGR.get(input.settings.sys_id)){

        saveGR.notification_email=input.settings.email;
        saveGR.batch_size=input.settings.batch;
        saveGR.enable_notifications=input.settings.notify;
        saveGR.detailed_logging=input.settings.logging;
        saveGR.date_format=input.settings.date_format;
        saveGR.timezone=input.settings.timezone;
        saveGR.theme=input.settings.theme;
        saveGR.update();

    }else{

        saveGR.initialize();
        saveGR.notification_email=input.settings.email;
        saveGR.batch_size=input.settings.batch;
        saveGR.enable_notifications=input.settings.notify;
        saveGR.detailed_logging=input.settings.logging;
        saveGR.date_format=input.settings.date_format;
        saveGR.timezone=input.settings.timezone;
        saveGR.theme=input.settings.theme;
        saveGR.insert();
    }

    data.saved=true;
}

})();
